// CHECK-NEXT:  [[ENTRY:.*:]]
// CHECK-NEXT:    [[COND1_ADDR:%.*]] = alloca i32, align 4
// CHECK-NEXT:    [[COND2_ADDR:%.*]] = alloca i32, align 4
// CHECK-NEXT:    [[COND3_ADDR:%.*]] = alloca i32, align 4
