// CHECK-NEXT:    [[B_ADDR:%.*]] = alloca i32, align 4
// CHECK-NEXT:    [[C_ADDR:%.*]] = alloca i32, align 4
// CHECK-NEXT:    [[D_ADDR:%.*]] = alloca i32, align 4
// CHECK-NEXT:    [[E_ADDR:%.*]] = alloca i32, align 4
