// CHECK-NEXT:    [[TMP1:%.*]] = call ptr @llvm.ct.select.p0(i1 [[TOBOOL]], ptr @fn_a, ptr @fn_b)
// CHECK-NEXT:    ret ptr [[TMP1]]
//
fnptr test_func_decay(int cond) {
  return __builtin_ct_select(cond, fn_a, fn_b);
}
